proof:
obtain ⟨ τ, hτ₁, hτ₂ ⟩ := hX;
filter_upwards [ hτ₁.tendsto_top ] with ω hω;
intro a
obtain ⟨ n, hn ⟩ : ∃ n, (a : WithTop ι) < τ n ω := by
  have := hω.eventually ( lt_mem_nhds ( show ( a : WithTop ι ) < ⊤ from WithTop.coe_lt_top a ) ) ; aesop;
have h_cont : ContinuousWithinAt (fun x => MeasureTheory.stoppedProcess (fun i => {ω' | ⊥ < τ n ω'}.indicator (X i)) (τ n) x ω) (Set.Ioi a) a := by
  exact hτ₂ n ω a |> ContinuousWithinAt.mono <| Set.Subset.refl _;
refine' h_cont.congr_of_eventuallyEq _ _;
· filter_upwards [ self_mem_nhdsWithin, mem_nhdsWithin_of_mem_nhds ( IsOpen.mem_nhds ( show IsOpen { x : ι | ( x : WithTop ι ) < τ n ω } from by
                                                                                        exact isOpen_lt ( by continuity ) ( by continuity ) ) hn ) ] with x hx₁ hx₂
  generalize_proofs at *;
  simp +decide [ MeasureTheory.stoppedProcess, hx₂.le, show ⊥ < τ n ω from lt_of_le_of_lt bot_le hn ];
· simp +decide [ MeasureTheory.stoppedProcess, hn.le ];
  rw [ Set.indicator_apply ] ; aesop

